+
+const reloadStatusFilename = "reload-status.json"
+
+type transactionalReloader struct {
+	mu        sync.RWMutex
+	status    api_v1.ReloadStatus
+	knownGood *config.Config
+	path      string
+	logger    *slog.Logger
+}
+
+func emptyReloadStatus() api_v1.ReloadStatus {
+	return api_v1.ReloadStatus{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}
+}
+
+func newTransactionalReloader(path string, logger *slog.Logger) *transactionalReloader {
+	r := &transactionalReloader{path: path, logger: logger, status: emptyReloadStatus()}
+	b, err := os.ReadFile(path)
+	if err != nil {
+		return r
+	}
+	var status api_v1.ReloadStatus
+	if err := json.Unmarshal(b, &status); err != nil {
+		logger.Warn("Ignoring corrupted transactional reload status", "file", path, "err", err)
+		return r
+	}
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMS == nil {
+		status.ReloaderTimingsMS = map[string]int64{}
+	}
+	r.status = status
+	return r
+}
+
+func (r *transactionalReloader) Status() api_v1.ReloadStatus {
+	r.mu.RLock()
+	defer r.mu.RUnlock()
+	status := r.status
+	status.AppliedReloaders = append([]string(nil), status.AppliedReloaders...)
+	status.ReloaderTimingsMS = make(map[string]int64, len(r.status.ReloaderTimingsMS))
+	for name, timing := range r.status.ReloaderTimingsMS {
+		status.ReloaderTimingsMS[name] = timing
+	}
+	return status
+}
+
+func (r *transactionalReloader) setKnownGood(conf *config.Config) {
+	r.mu.Lock()
+	defer r.mu.Unlock()
+	r.knownGood = conf
+}
+
+func (r *transactionalReloader) reload(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) error {
+	logger.Info("Loading configuration file", "filename", filename)
+	conf, err := config.LoadFile(filename, agentMode, logger)
+	if err != nil {
+		r.record(api_v1.ReloadStatus{LastReloadID: time.Now().UTC().Format(time.RFC3339), ErrorCategory: "load_error", ErrorMessage: fmt.Sprintf("couldn't load configuration (--config.file=%q): %v", filename, err), AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}})
+		configSuccess.Set(0)
+		callback(false)
+		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	status := emptyReloadStatus()
+	status.LastReloadID = time.Now().UTC().Format(time.RFC3339)
+	for _, rl := range rls {
+		start := time.Now()
+		err := rl.reloader(conf)
+		status.ReloaderTimingsMS[rl.name] = time.Since(start).Milliseconds()
+		if err != nil {
+			status.ErrorCategory = "apply_error"
+			status.ErrorMessage = err.Error()
+			status.FailedReloader = rl.name
+			if len(status.AppliedReloaders) > 0 {
+				status.RollbackAttempted = true
+				status.RollbackSuccessful = r.rollback(rls)
+				if !status.RollbackSuccessful {
+					status.ErrorCategory = "rollback_error"
+				}
+			}
+			r.record(status)
+			configSuccess.Set(0)
+			callback(false)
+			return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, err)
+		}
+		status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
+	}
+
+	status.LastReloadSuccessful = true
+	r.record(status)
+	r.setKnownGood(conf)
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	configSuccess.Set(1)
+	configSuccessTime.SetToCurrentTime()
+	callback(true)
+	return nil
+}
+
+func (r *transactionalReloader) rollback(rls []reloader) bool {
+	r.mu.RLock()
+	conf := r.knownGood
+	r.mu.RUnlock()
+	if conf == nil {
+		return false
+	}
+	for _, rl := range rls {
+		if err := rl.reloader(conf); err != nil {
+			r.logger.Error("Failed to roll back configuration", "reloader", rl.name, "err", err)
+			return false
+		}
+	}
+	return true
+}
+
+func (r *transactionalReloader) record(status api_v1.ReloadStatus) {
+	r.mu.Lock()
+	r.status = status
+	b, err := json.Marshal(status)
+	if err == nil {
+		err = os.MkdirAll(filepath.Dir(r.path), 0o755)
+	}
+	if err == nil {
+		err = os.WriteFile(r.path, b, 0o644)
+	}
+	r.mu.Unlock()
+	if err != nil {
+		r.logger.Error("Failed to persist transactional reload status", "file", r.path, "err", err)
+	}
+}
